          <div className="grid lg:grid-cols-4 gap-20 mb-20">
            <div className="lg:col-span-2 space-y-10">
              <div className="flex items-center space-x-3 group cursor-pointer">
                <LogoMotion isScrolled={false} />
                <span className="font-bold text-4xl tracking-tight">PHIL Inc.</span>
              </div>
              <div className="flex gap-6">
                <a href={FACEBOOK_URL} target="_blank" rel="noopener noreferrer" className="w-14 h-14 bg-white/5 rounded-2xl flex items-center justify-center hover:bg-medicalBlue transition-all"><Facebook className="w-6 h-6" /></a>
                <a href={LINKEDIN_URL} target="_blank" rel="noopener noreferrer" className="w-14 h-14 bg-white/5 rounded-2xl flex items-center justify-center hover:bg-medicalBlue transition-all"><Linkedin className="w-6 h-6" /></a>
