          <div className="pt-20 border-t border-white/5 text-center text-gray-500 text-sm tracking-widest">
            <p>© 2026 PROGRESSIVE HEALTH INITIATIVE OF LIBERIA (PHIL INC.)</p>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

